SELECT count(comment_id)
FROM reply
WHERE comment_id = #{commentId};

SELECT comment_id
FROM comment
WHERE repo_id = #{repoId}
  AND dis_id = #{disId}
  AND pr_id = #{prId}

mapper.update:
UPDATE pr
SET base_sha  = #{baseSha},
    head_sha  = #{headSha},
    start_sha = #{startSha}
WHERE repo_id = #{repoId}
  AND pr_id = #{prId}

UPDATE pr_temp
    SET temp_status = 1
WHERE
    repo_id = #{repoId}
  AND
    pr_id = #{prId}
